create table paymob_orders (
    order_id   number generated by default as identity not null enable,
    amount     number,
    status     varchar2(30 byte),
    created_at timestamp(6) with local time zone default sysdate
);

create unique index paymob_orders_con on
    paymob_orders (
        order_id
    );

alter table paymob_orders
    add constraint paymob_orders_con primary key ( order_id )
        using index paymob_orders_con enable;

